    hexi::reader reader(buffer);
    NetworkPacket packet;

    // Read the packet_id
    packet.packet_id = reader.read<uint32_t>();

    // Read the username using the length prefix
    packet.username = reader.read<hexi::prefixed<std::string>>();

    // Read the score count, then use read_container to read the scores vector
    packet.scores = reader.read_container<std::vector<uint32_t>>();

    // Read the metadata string as null-terminated for zero-copy
    packet.metadata = reader.read<hexi::null_terminated<std::string>>();

    // Skip any remaining padding bytes (if any)
    if (reader.remaining() > 0) {
        reader.skip(reader.remaining());
    }

    return packet;
}

