    hexi::reader reader(buffer);
    PacketInfo info;

    // Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    auto packet_id_span = reader.span(sizeof(uint32_t));
    std::memcpy(&info.packet_id, packet_id_span.data(), sizeof(uint32_t));

    // Read username using prefixed adaptor to get a string_view
    info.username = reader.read<hexi::prefixed<std::string_view>>();

    // Skip the scores vector without reading its elements
    // Read count, then skip the data
    uint32_t score_count = reader.read<uint32_t>();
    reader.skip(score_count * sizeof(uint32_t));

    return info;
}

