template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT result = 0;
    int shift = 0;

    while (true) {
        uint8_t byte;
        reader.read(&byte, 1);

        // Extract lower 7 bits and combine with result
        result |= static_cast<UnsignedT>(byte & 0x7F) << shift;

        // If MSB is 0, this is the last byte
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
    }

    return static_cast<T>(result);
