#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Const version for serialization (writing)
    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Write number of temperatures
        adaptor.write(static_cast<uint32_t>(temperatures.size()));

        // Convert each temperature from native to little-endian and write
        for (const auto& temp : temperatures) {
            auto converted = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(converted);
        }

        // Convert pressure from native to little-endian and write
        auto converted_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    // Non-const version for deserialization (reading)
    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read number of temperatures
        uint32_t count;
        adaptor.read(count);

        // Read temperatures and convert from little-endian to native
        temperatures.resize(count);
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::little_to_native_inplace(temp);
        }

        // Read pressure and convert from little-endian to native
        adaptor.read(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    hexi::buffer_ostream stream;
    stream.serialise(data);
    return stream.data();
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_istream stream(buffer);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_istream stream(buffer);
    SensorInfo info;

    // Extract null-terminated sensor name string (if present)
    info.sensor_name = stream.view();

    // Check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(info.sensor_id);

    // Skip remaining data
    if (stream.remaining() > 0) {
        stream.skip(stream.remaining());
    }

    return info;
}

